import json
import psycopg2
import boto3
import logging
import os
import zipfile
import pandas as pd
from io import BytesIO
from utility.archive import archive
logger = logging.getLogger()
logger.setLevel(logging.INFO)
s3 = boto3.client("s3")
def flatten(filedata,conn,curr):
    filename=filedata[0]
    fil=filename.split(".")[0]
    filekey=filedata[4]
    bucketname=filedata[1]
    obj = s3.get_object(Bucket=bucketname, Key=filekey)
    excel_data = obj['Body'].read()
    excelsheets=pd.ExcelFile(BytesIO(excel_data))
    path=filekey.split("/")
    arrdatetime=filedata[6].replace(" ","").replace(":","").replace("-","") #Considering lastModified time of file arrival
    pathbroke=''
    count=0
    for i in range(len(path)):
        if path[i]=='Land':
            count=i
            break
        pathbroke=f"{pathbroke}{path[i]}/"
    count+=1
    destpath=f"{pathbroke}Processed/ExcelCSV/"
    for i in range(count,len(path)-1):
        destpath=f"{destpath}{path[i]}/"
    destpath=f"{destpath}{fil}/{arrdatetime}/"
    for sheet_name in excelsheets.sheet_names:
        sheet=pd.read_excel(excelsheets,sheet_name=sheet_name)
        exdata=BytesIO()
        sheet.to_csv(exdata,index=False)
        s3.put_object(Bucket=bucketname,Key=f"{destpath}{sheet_name}.csv",Body=exdata.getvalue())
        logger.info(f"Sheet {sheet_name} has been flattened to {destpath}")
    # curr.execute("""update public.intrn_kna_nitya_lambdards set filestatus ='Flattened' where filekey = (%s);""",(filekey,))
    archive(filedata,conn,curr)